import { Component, h, Prop } from '@stencil/core';
import { WdprProgressIndicatorPosition, WdprProgressSegmentStatus } from '../../models/progress-bar.model';

@Component({
  tag: 'wdpr-progress-segment',
  shadow: true,
})
export class WdprProgressSegment {
  @Prop({ reflect: true }) status: WdprProgressSegmentStatus = 'pending';
  @Prop({ reflect: true }) position: WdprProgressIndicatorPosition = 'middle';

  private get _isFilled(): boolean {
    return this.status === 'active' || this.status === 'complete';
  }

  private get _bgClass(): string {
    return this._isFilled ? 'bg-surface-neutral-extra-dark' : 'bg-surface-neutral-light';
  }

  private get _roundingClass(): string {
    if (this.position === 'start') return 'rounded-l-pill';
    if (this.position === 'end') return 'rounded-r-pill';

    return '';
  }

  private get _terminatorClass(): string {
    switch (this.position) {
      case 'start':
        // Start segments have a diagonal cut on the right side only
        return '[clip-path:polygon(0%_0%,100%_0%,calc(100%-var(--wdpr-terminator))_100%,0%_100%)]';
      case 'end':
        // End segments have a diagonal cut on the left side only
        return '[clip-path:polygon(var(--wdpr-terminator)_0%,100%_0%,100%_100%,0%_100%)]';

      case 'middle':
      default:
        // Middle segments have diagonal cuts on both sides
        return '[clip-path:polygon(var(--wdpr-terminator)_0%,100%_0%,calc(100%-var(--wdpr-terminator))_100%,0%_100%)]';
    }
  }

  render() {
    return (
      <div
        class={`relative h-075 w-full ${this._bgClass} ${this._roundingClass} ${this._terminatorClass}`}
        part="segment"
        aria-hidden="true"
        style={{ '--wdpr-terminator': 'var(--theme-dimension-075)' }}
      >
        {this.status !== 'complete' && this.position === 'end' && (
          <div
            class="absolute top-[1px] right-[1px] w-dimension-050 h-dimension-050 shrink-0 bg-surface-neutral-extra-dark rounded-pill"
            part="stop-indicator"
          ></div>
        )}
      </div>
    );
  }
}
